import React, { useState } from 'react';
import axios from 'axios';

const exifFields = [
    "ImageWidth",
    "ImageHeight",
    "Make",
    "Model",
    "DateTimeOriginal",
    "GPSLatitude",
    "GPSLongitude",
    "FocalLength",
    "ApertureValue",
    "ISO",
];

const ExifForm = (axiosInstance) => {
    const [selectedFields, setSelectedFields] = useState([]);
    const [checkAll, setCheckAll] = useState(false);

    // Handle checkbox toggle
    const handleCheckboxChange = (field) => {
        setSelectedFields((prev) =>
            prev.includes(field)
                ? prev.filter((item) => item !== field)
                : [...prev, field]
        );
    };

    // Handle "Check All" toggle
    const handleCheckAll = () => {
        if (checkAll) {
            setSelectedFields([]);
        } else {
            setSelectedFields(exifFields);
        }
        setCheckAll(!checkAll);
    };

    // Handle form submission
    const handleSubmit = async (e) => {
        e.preventDefault();
        try {
            console.log
            const jsonPathQuery = selectedFields.map((field) => `$..${field}`);
            const response = await axiosInstance.get('/query', {
                jsonPathQuery,
            });
            console.log('Response:', response.data);
        } catch (error) {
            console.error('Error submitting form:', error);
        }
    };

    return (
        <form onSubmit={handleSubmit} style={{ padding: '20px', border: '1px solid #ccc', borderRadius: '5px', maxWidth: '400px', margin: 'auto', backgroundColor: '#f9f9f9' }}>
            <h3 style={{ textAlign: 'center', color: '#333' }}>Select EXIF Fields to Query</h3>
            <div style={{ marginBottom: '10px' }}>
                <label style={{ display: 'flex', alignItems: 'center' }}>
                    <input
                        type="checkbox"
                        checked={checkAll}
                        onChange={handleCheckAll}
                        style={{ marginRight: '10px' }}
                    />
                    Check All
                </label>
            </div>
            <div style={{ marginBottom: '20px' }}>
                {exifFields.map((field) => (
                    <label key={field} style={{ display: 'flex', alignItems: 'center', marginBottom: '5px', padding: '5px', border: '1px solid #ddd', borderRadius: '3px', backgroundColor: '#fff' }}>
                        <input
                            type="checkbox"
                            value={field}
                            checked={selectedFields.includes(field)}
                            onChange={() => handleCheckboxChange(field)}
                            style={{ marginRight: '10px' }}
                        />
                        {field}
                    </label>
                ))}
            </div>
            <button type="submit" style={{ display: 'block', width: '100%', padding: '10px', backgroundColor: '#007bff', color: '#fff', border: 'none', borderRadius: '5px', cursor: 'pointer' }}>
                Submit Query
            </button>
        </form>
    );
};

export default ExifForm;
